def greg_jd(y,m,d):
    if m<=2: y-=1; m+=12
    A=y//100; B=2-A+A//4
    return int(365.25*(y+4716))+int(30.6001*(m+1))+d+B-1524

def jd_greg(jd):
    a=int(jd)+32044
    b=(4*a+3)//146097
    c=a-(146097*b)//4
    d=(4*c+3)//1461
    e=c-(1461*d)//4
    m=(5*e+2)//153
    day=e-(153*m+2)//5+1
    month=m+3-12*(m//10)
    year=100*b+d-4800+(m//10)
    return year,month,day

def iter_lunar_months(ly_num):
    current_year=ly_num-1
    for mo,start,days,is_l in LY_DATA[ly_num][3]:
        if mo==1 and not is_l:
            current_year+=1
        yield current_year,mo,start,days,is_l

class Solar:
    __slots__=("year","month","day","hour","minute","second","jd")
    def __init__(self,y,mo,d,h=0,mi=0,s=0):
        self.year=y; self.month=mo; self.day=d
        self.hour=h; self.minute=mi; self.second=s
        self.jd=greg_jd(y,mo,d)
    @staticmethod
    def fromYmdHms(y,mo,d,h,mi,s): return Solar(y,mo,d,h,mi,s)
    def getLunar(self): return Lunar._from_solar(self)
    def getYear(self): return self.year
    def getMonth(self): return self.month
    def getDay(self): return self.day
    def getHour(self): return self.hour
    def getMinute(self): return self.minute
    def getSecond(self): return self.second
    def getJulianDay(self): return float(self.jd)
    def toYmd(self): return f"{self.year:04d}{self.month:02d}{self.day:02d}"
    def subtract(self,o): return self.jd-o.jd
    def next(self,n): y,m,d=jd_greg(self.jd+n); return Solar(y,m,d,self.hour,self.minute,self.second)

class Lunar:
    __slots__=("year","month","day","hour","minute","second","isLeap","_s","_yg","_yz","_yg_ex","_yz_ex","_mg","_mz","_mg_ex","_mz_ex","_dg","_dz","_dg_ex","_dz_ex","_tg","_tz","_yh","_mh","_dh","_th","_yn","_mn","_dn","_tn","_yxk","_mxk","_dxk","_txk","_sx","_ty","_tx","_mgong","_sgong")
    def __init__(self,ly,lm,ld,h=0,mi=0,s=0,leap=False):
        self.year=ly; self.month=lm; self.day=ld
        self.hour=h; self.minute=mi; self.second=s; self.isLeap=leap
        self._s=self._to_solar()
        self._compute()
    def _to_solar(self):
        for lunar_year,mo,start,days,is_l in iter_lunar_months(self.year):
            if lunar_year==self.year and mo==self.month and is_l==self.isLeap:
                y,m,d=jd_greg(int(start)+self.day-1)
                return Solar(y,m,d,self.hour,self.minute,self.second)
        y,m,d=jd_greg(int(LY_DATA[self.year][2]))
        return Solar(y,m,d,self.hour,self.minute,self.second)
    @staticmethod
    def _from_solar(s):
        jd=s.jd
        for ly_num in (s.year, s.year+1, s.year-1):
            if ly_num not in LY_DATA: continue
            for lunar_year,mo,start,days,is_l in iter_lunar_months(ly_num):
                if start <= jd < start+days:
                    day=int(jd-start)+1
                    return Lunar(lunar_year,mo,day,s.hour,s.minute,s.second,is_l)
        return Lunar(s.year,1,1,s.hour,s.minute,s.second,False)
    def _compute(self):
        s=self._s; ly=self.year
        lc_ymd=int(LICHUN_YMD.get(s.year,"20000204"))
        lc_jd=LICHUN_JD.get(s.year,2446831.0)
        s_ymd=int(s.toYmd())
        s_jd=s.jd-0.5+(s.hour*3600+s.minute*60+s.second)/86400
        before_lichun=s_ymd<lc_ymd or (s_ymd==lc_ymd and s_jd<lc_jd)
        yg=(ly-4)%10; yz=(ly-4)%12
        g_ex=yg; z_ex=yz
        if ly==s.year:
            if before_lichun: g_ex-=1; z_ex-=1
        elif ly<s.year:
            if not before_lichun: g_ex+=1; z_ex+=1
        def m10(x): return (x+10)%10
        def m12(x): return (x+12)%12
        self._yg=STEMS[yg%10]; self._yz=ZHI[yz%12]
        self._yg_ex=STEMS[m10(g_ex)]; self._yz_ex=ZHI[m12(z_ex)]
        gi=SI[self._yg_ex]; g_off=(((gi%5)+1)*2)%10; mi0=11 if self.month==1 and before_lichun else self.month-1
        self._mg=STEMS[(g_off+mi0)%10]; self._mz=ZHI[(2+mi0)%12]
        self._mg_ex=STEMS[(g_off+mi0)%10]; self._mz_ex=ZHI[(2+mi0)%12]
        noon=Solar(s.year,s.month,s.day,12,0,0); di=noon.jd-DAY_EPOCH_JD
        dg=int(di)%10; dz=int(di)%12
        self._dg=STEMS[dg]; self._dz=ZHI[dz]
        dg_ex=dg; dz_ex=dz
        hm=f"{self.hour:02d}:{self.minute:02d}"
        if "23:00"<=hm<="23:59": dg_ex=(dg_ex+1)%10; dz_ex=(dz_ex+1)%12
        self._dg_ex=STEMS[dg_ex]; self._dz_ex=ZHI[dz_ex]
        tzi=0 if self.hour==23 else (self.hour+1)//2
        self._tz=ZHI[tzi]; self._tg=STEMS[(dg_ex*2+tzi)%10]
        self._yh=ZHI_HIDE.get(self._yz,[]); self._mh=ZHI_HIDE.get(self._mz,[])
        self._dh=ZHI_HIDE.get(self._dz,[]); self._th=ZHI_HIDE.get(self._tz,[])
        def nay(g,z): k=g+z; return NAYIN.get(k,NAYIN.get(z+g,"土"))
        self._yn=nay(self._yg,self._yz); self._mn=nay(self._mg,self._mz)
        self._dn=nay(self._dg,self._dz); self._tn=nay(self._tg,self._tz)
        def xk(g,z):
            xs={"甲":0,"乙":0,"丙":2,"丁":2,"戊":4,"己":4,"庚":6,"辛":6,"壬":8,"癸":8}
            xi=xs.get(g,0); zi2=ZI[z]; diff=(zi2-xi)%12
            return ZHI[(zi2+10-diff)%12]+ZHI[(zi2+11-diff)%12]
        xk_v=xk(self._dg,self._dz)
        self._yxk=xk_v; self._mxk=xk_v; self._dxk=xk_v; self._txk=xk_v
        self._sx=ZHI_ZOO.get(self._yz,"鼠")
        self._ty=STEMS[(SI[self._mg]+1)%10]+ZHI[(ZI[self._mz]+3)%12]
        self._tx=STEMS[(SI[self._dg]+1)%10]+ZHI[(ZI[self._dz]+3)%12]
        mg_zi=(14-ZI[self._mz]-ZI[self._tz])%12
        self._mgong=STEMS[(yg*2+mg_zi)%10]+ZHI[mg_zi]
        sg_zi=(ZI[self._mz]+ZI[self._tz]+2)%12
        self._sgong=STEMS[(ZI[self._mz]+sg_zi)%10]+ZHI[sg_zi]
    # Public API
    def getYearGan(self): return self._yg
    def getYearZhi(self): return self._yz
    def getYearGanExact(self): return self._yg_ex
    def getYearZhiExact(self): return self._yz_ex
    def getYearInGanZhi(self): return self._yg+self._yz
    def getYearInGanZhiExact(self): return self._yg_ex+self._yz_ex
    def getMonthGan(self): return self._mg
    def getMonthZhi(self): return self._mz
    def getMonthGanExact(self): return self._mg_ex
    def getMonthZhiExact(self): return self._mz_ex
    def getMonthInGanZhi(self): return self._mg+self._mz
    def getMonthInGanZhiExact(self): return self._mg_ex+self._mz_ex
    def getDayGan(self): return self._dg
    def getDayZhi(self): return self._dz
    def getDayGanExact(self): return self._dg_ex
    def getDayZhiExact(self): return self._dz_ex
    def getDayInGanZhi(self): return self._dg+self._dz
    def getDayInGanZhiExact(self): return self._dg_ex+self._dz_ex
    def getTimeGan(self): return self._tg
    def getTimeZhi(self): return self._tz
    def getTimeInGanZhi(self): return self._tg+self._tz
    def getYearShengXiao(self): return self._sx
    def getYearHideGan(self): return self._yh
    def getMonthHideGan(self): return self._mh
    def getDayHideGan(self): return self._dh
    def getTimeHideGan(self): return self._th
    def getYearNaYin(self): return self._yn
    def getMonthNaYin(self): return self._mn
    def getDayNaYin(self): return self._dn
    def getTimeNaYin(self): return self._tn
    def getYearXunKong(self): return self._yxk
    def getMonthXunKong(self): return self._mxk
    def getDayXunKong(self): return self._dxk
    def getTimeXunKong(self): return self._txk
    def getSolar(self): return self._s
    def getEightChar(self): return EightChar(self)
    def toString(self): leap_str="闰" if self.isLeap else ""; return f"{self.year}年{leap_str}{self.month}月{self.day}日"

