class Yun:
    __slots__=("_l","_g","_f","_sy","_sm")
    def __init__(self,l,g):
        self._l=l; self._g=g
        dg=l.getDayGanExact(); yang=SI[dg]%2==0; man=(g==1)
        self._f=(yang and man)or(not yang and not man)
        self._sy=l.year+1; self._sm=l.month
    def getStartYear(self): return self._sy
    def getStartMonth(self): return self._sm
    def getDaYun(self,n=10): return [DaYun(self,i) for i in range(n)]

class DaYun:
    __slots__=("_y","_i","_gz","_sy","_ea","_ey","_xk")
    def __init__(self,y,i):
        self._y=y; self._i=i
        l=y._l; dg=l.getDayGanExact(); dz=l.getDayZhiExact()
        s=1 if y._f else -1; gi=SI[dg]; zi=ZI[dz]; n=i+1
        self._gz=STEMS[(gi+s*n)%10]+ZHI[(zi+s*n)%12]
        self._sy=l.year+1+i*10; self._ea=1+i*10; self._ey=self._sy+9
        xs={"甲":0,"乙":0,"丙":2,"丁":2,"戊":4,"己":4,"庚":6,"辛":6,"壬":8,"癸":8}
        xi=xs.get(dg,0); zi2=ZI[dz]; diff=(zi2-xi)%12
        self._xk=ZHI[(zi2+10-diff)%12]+ZHI[(zi2+11-diff)%12]
    def getGanZhi(self): return self._gz
    def getStartYear(self): return self._sy
    def getEndYear(self): return self._ey
    def getStartAge(self): return self._ea
    def getEndAge(self): return self._ea+9
    def getXunKong(self): return self._xk
    def getIndex(self): return self._i
